const body = $input.first().json.body || $input.first().json;
const event = body.event;
const data = body.data;

if (event !== 'messages.upsert') return [];

const fromMe = data?.key?.fromMe;
if (fromMe) return [];

const remoteJid = data?.key?.remoteJid || '';
if (remoteJid.endsWith('@g.us')) return [];

const msg = data?.message || {};
const text = msg.conversation || msg.extendedTextMessage?.text || msg.imageMessage?.caption || msg.videoMessage?.caption || '';

if (!text.trim()) return [];

const phone = remoteJid.replace('@s.whatsapp.net', '').replace('@c.us', '');
const pushName = data?.pushName || '';
const messageId = data?.key?.id || '';
const timestamp = data?.messageTimestamp ? new Date(data.messageTimestamp * 1000).toISOString() : new Date().toISOString();

return [{json: { phone, pushName, messageId, text: text.trim(), timestamp, remoteJid, instance: body.instance || '{{ AGENT_ID }}' }}];

const now = new Date();
const fmt = new Intl.DateTimeFormat('en-US', { timeZone: 'America/Sao_Paulo', weekday: 'short', hour: '2-digit', hour12: false });
const parts = fmt.formatToParts(now);
const weekday = parts.find(p => p.type === 'weekday')?.value || '';
const hour = parseInt(parts.find(p => p.type === 'hour')?.value || '0');
const isWeekday = !['Sat', 'Sun'].includes(weekday);
const isBusinessHour = hour >= 8 && hour < 18;
const isWithinHours = isWeekday && isBusinessHour;

const input = $input.first().json;
return [{json: { ...input, within_business_hours: isWithinHours, current_weekday: weekday, current_hour: hour }}];

const inbound = $('Business Hours Check').first().json;
const promptRow = $('Get Active Prompt').first().json;
const historyResp = $('Get Conversation History').first().json;
const contextResp = $('Get Lead Context').first().json;
const plansResp = $('Get Plans (Tool)').first().json;
const accountResp = $('Check Account (Tool)').first().json;

const history = Array.isArray(historyResp) ? historyResp : (historyResp?.data || []);
const ctxArr = Array.isArray(contextResp) ? contextResp : (contextResp?.data || []);
const leadCtxRow = ctxArr[0] || {};
const leadContext = leadCtxRow.lead_context || {};
const stage = leadCtxRow.conversation_stage || 'new';
const companyName = leadCtxRow.company_name || '';
const decisionMaker = leadCtxRow.decision_maker_name || inbound.pushName || '';

const systemPrompt = promptRow?.system_prompt || 'Você é uma assistente comercial do Sondar+.';
const modelPrimary = promptRow?.model_primary || 'gemini-2.0-flash';
const temperature = promptRow?.temperature || 0.4;
const maxTokens = promptRow?.max_tokens || 300;

const historyChronological = history.slice().reverse();
const contextLines = historyChronological.map(m => {
  const role = m.direction === 'outbound' ? 'Ana' : (decisionMaker || 'Cliente');
  return role + ': ' + m.content;
}).join('\n');

const leadBrief = [
  decisionMaker ? 'Nome: ' + decisionMaker : null,
  companyName ? 'Empresa: ' + companyName : null,
  leadCtxRow.city ? 'Cidade: ' + leadCtxRow.city : null,
  'Stage: ' + stage,
  leadContext.persona_fit != null ? 'Persona fit: ' + leadContext.persona_fit + '/100' : null,
  leadContext.pain_points?.length ? 'Dores detectadas: ' + leadContext.pain_points.join('; ') : null,
  leadContext.objections?.length ? 'Objeções: ' + leadContext.objections.join('; ') : null,
  leadContext.signals ? 'Sinais: ' + JSON.stringify(leadContext.signals) : null,
  leadContext.next_action ? 'Próxima ação sugerida: ' + leadContext.next_action : null,
  leadContext.last_summary ? 'Resumo: ' + leadContext.last_summary : null,
].filter(Boolean).join('\n');

// Tabela de planos direto do DB (fonte da verdade, nada hardcoded)
let planosTxt = '';
try {
  const plans = plansResp?.planos || [];
  planosTxt = plans.map(p => {
    const limits = p.ilimitado
      ? 'ilimitado'
      : [
          p.max_obras ? p.max_obras + ' obras' : null,
          p.max_furos ? p.max_furos + ' furos' : null,
          p.max_usuarios ? p.max_usuarios + ' usuários' : null,
        ].filter(Boolean).join(' / ');
    return '- ' + p.nome + ' (R$' + p.preco_brl + '/' + (p.billing || 'mensal') + '): ' + limits;
  }).join('\n');
} catch(e) {}

// Account status
let accountTxt = '';
try {
  if (accountResp?.tem_conta) {
    const c = accountResp.contas?.[0];
    if (c) {
      accountTxt = 'JÁ É CLIENTE: ' + c.empresa + ' (' + (c.cidade || '?') + ')';
      if (c.plano) accountTxt += ', plano ' + c.plano.nome;
      if (c.assinatura?.trial_ativo) accountTxt += ', trial ativo até ' + c.assinatura.trial_termina_em;
    }
  } else {
    accountTxt = 'AINDA NÃO É CLIENTE (lead novo, sem cadastro no Sondar+)';
  }
} catch(e) {}

const userMessage = (decisionMaker || 'Cliente') + ' (' + inbound.phone + ') escreveu agora:\n\n' + inbound.text;

const parts = [];
if (leadBrief) parts.push('PERFIL DO LEAD:\n' + leadBrief);
if (accountTxt) parts.push('STATUS DE CONTA:\n' + accountTxt);
if (planosTxt) parts.push('PLANOS ATIVOS (fonte oficial, use SEMPRE esses valores):\n' + planosTxt);
if (contextLines) parts.push('HISTÓRICO RECENTE DA CONVERSA:\n' + contextLines);
parts.push('NOVA MENSAGEM:\n' + userMessage);
const fullContext = parts.join('\n\n---\n\n');

return [{json: {
  phone: inbound.phone,
  pushName: decisionMaker,
  messageId: inbound.messageId,
  lead_id: leadCtxRow.id,
  system_prompt: systemPrompt,
  user_message: fullContext,
  model: modelPrimary,
  temperature,
  max_tokens: maxTokens
}}];

const geminiResp = $input.first().json;
const inbound = $('Build Prompt + History').first().json;

let aiText = '';
try {
  aiText = geminiResp?.candidates?.[0]?.content?.parts?.[0]?.text || '';
} catch (e) {}

// Parse escalation marker: <<ESCALAR:reason:summary>>
let escalation = null;
const escMatch = aiText.match(/<<ESCALAR:([a-z_]+):([^>]+)>>/i);
if (escMatch) {
  escalation = {
    reason: escMatch[1].toLowerCase(),
    summary: escMatch[2].trim()
  };
  aiText = aiText.replace(escMatch[0], '').trim();
}

// Sanitize
aiText = aiText.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();
aiText = aiText.replace(/<\/?final>/gi, '').trim();
aiText = aiText.replace(/^Ana:\s*/i, '').trim();
aiText = aiText.replace(/```[\s\S]*?```/g, '').trim();

if (!aiText) aiText = 'Oi! Só um momento, já te respondo.';

const textLen = aiText.length;
const delay_ms = Math.min(Math.max(textLen * 60 + 800, 2000), 12000);

return [{json: {
  phone: inbound.phone,
  messageId: inbound.messageId,
  lead_id: inbound.lead_id,
  ai_text: aiText,
  delay_ms,
  text_length: textLen,
  delay_seconds: Math.floor(delay_ms / 1000),
  escalation_reason: escalation?.reason || null,
  escalation_summary: escalation?.summary || null,
  should_escalate: escalation !== null
}}];

