const inbound = $('Extract WhatsApp Data').first().json;

// Timezone America/Sao_Paulo
function nowInBrasilia() {
  const now = new Date();
  const parts = new Intl.DateTimeFormat('en-US', {
    timeZone: 'America/Sao_Paulo',
    year: 'numeric', month: '2-digit', day: '2-digit',
    hour: '2-digit', minute: '2-digit', hour12: false, weekday: 'short'
  }).formatToParts(now);
  const get = (t) => parts.find(p => p.type === t)?.value;
  return {
    weekday: get('weekday'), // Sun, Mon, ...
    hour: parseInt(get('hour') || '0'),
    year: parseInt(get('year')),
    month: parseInt(get('month')),
    day: parseInt(get('day'))
  };
}

function nextBusinessDay9h() {
  const b = nowInBrasilia();
  const WEEKDAY_NUM = {Sun:0, Mon:1, Tue:2, Wed:3, Thu:4, Fri:5, Sat:6};
  let dow = WEEKDAY_NUM[b.weekday];
  const isBusinessDay = (dow >= 1 && dow <= 5);
  const hour = b.hour;

  // Same day if: é dia útil E ainda antes das 8h
  if (isBusinessDay && hour < 8) {
    const iso = new Date(Date.UTC(b.year, b.month - 1, b.day, 12, 0, 0)).toISOString();
    // 9h Brasília = 12h UTC (GMT-3)
    return iso;
  }

  // Senão: próximo dia útil
  let daysToAdd = 1;
  let testDow = (dow + daysToAdd) % 7;
  while (testDow === 0 || testDow === 6) {
    daysToAdd++;
    testDow = (dow + daysToAdd) % 7;
  }

  const target = new Date(Date.UTC(b.year, b.month - 1, b.day, 12, 0, 0));
  target.setUTCDate(target.getUTCDate() + daysToAdd);
  return target.toISOString();
}

const scheduled_for = nextBusinessDay9h();

return [{json: {
  ...inbound,
  scheduled_for,
  queue_message_type: 'reply_pending',
  queue_content: inbound.text
}}];
